 25	import NetflowTrafficParent from '../components/netflow-traffic-parent';
 26	import NetflowTab from '../components/netflow-traffic-tab';
 27	import { ContextSingleton } from '../utils/context';
 28	import Header from './header';
 29	
 30	import '@patternfly/patternfly/patternfly-charts-theme-dark.css';
 31	import '@patternfly/patternfly/patternfly-theme-dark.css';
 32	import '@patternfly/react-core/dist/styles/base.css';
 33	import './index.css';
 34	
 35	configure({ isolateGlobalState: true });
 36	
 37	const allPages = [
 38	  {
 39	    id: 'netflow-traffic',
 40	    name: 'Network Traffic',
 41	    content: <NetflowTrafficParent />
 42	  },
 43	  {
 44	    id: 'pod-tab',
 45	    name: 'Pod tab',
 46	    content: <NetflowTab obj={{ kind: 'Pod', metadata: { name: 'test', namespace: 'default' } }} />,
 47	    addContext: true
 48	  },
 49	  {
 50	    id: 'namespace-tab',
 51	    name: 'Namespace tab',
 52	    content: <NetflowTab obj={{ kind: 'Namespace', metadata: { name: 'test' } }} />,
 53	    addContext: true
 54	  },
 55	  {
 56	    id: 'node-tab',
 57	    name: 'Node tab',
 58	    content: <NetflowTab obj={{ kind: 'Node', metadata: { name: 'test' } }} />,
 59	    addContext: true
 60	  },
 61	  {
 62	    id: 'dev-tab',
 63	    name: 'Dev tab',
 64	    content: (
 65	      <NetflowTrafficDevTab
 66	        match={{
 67	          path: '/dev-monitoring/ns/:ns',
 68	          url: '/dev-monitoring/ns/netobserv',
 69	          isExact: false,
 70	          params: {
 71	            ns: 'netobserv'
 72	          }
 73	        }}
 74	      />
 75	    ),
 76	    addContext: true
 77	  },
 78	  {
 79	    id: 'udn-tab',
 80	    name: 'UDN tab',
 81	    content: <NetflowTab obj={{ kind: 'UserDefinedNetwork', metadata: { name: 'my-udn', namespace: 'default' } }} />,
 82	    addContext: true
 83	  },
 84	  {
 85	    id: 'network-health',
 86	    name: 'Network Health',
 87	    content: <NetworkHealth />
 88	  },
 89	  {
 90	    id: 'flowCollector-wizard',
 91	    name: 'FlowCollector wizard',
 92	    content: <FlowCollectorWizard name="cluster" />
 93	  },
 94	  {
 95	    id: 'flowCollector',
 96	    name: 'FlowCollector form',
 97	    content: <FlowCollectorForm name="cluster" />
 98	  },
 99	  {
100	    id: 'flowCollector-status',
101	    name: 'FlowCollector status',
102	    content: <FlowCollectorStatus />
103	  },
104	  {
105	    id: 'flowCollectorSlice',
106	    name: 'FlowCollectorSlice form',
107	    content: <FlowCollectorSliceForm name="flowCollectorSlice-sample" />
108	  },
109	  {
110	    id: 'flowMetric-wizard',
111	    name: 'FlowMetric wizard',
112	    content: <FlowMetricWizard name="flowmetric-sample" />
113	  },
114	  {
115	    id: 'flowMetric',
116	    name: 'FlowMetric form',
117	    content: <FlowMetricForm name="flowmetric-sample" />
118	  }
119	];
120	const endUserPages = allPages.filter(p => p.id === 'netflow-traffic' || p.id === 'network-health');
121	
122	export const App: React.FunctionComponent<{ endUser?: boolean }> = ({ endUser }) => {
123	  const [isSidebarOpen, setIsSidebarOpen] = React.useState(true);
124	  const [isDark, setDark] = React.useState(false);
125	  ContextSingleton.setStandalone();
126	  const pages = endUser ? endUserPages : allPages;
127	
128	  const onSidebarToggle = () => {
129	    setIsSidebarOpen(!isSidebarOpen);
130	  };
131	
132	  const withContext = (content: JSX.Element, name: string) => {
133	    return (
134	      <PageSection id="netobservPageSection" className={`tab ${isDark ? 'dark' : 'light'}`}>
135	        <div style={{ padding: '1rem' }}>
136	          <Title headingLevel="h1">{`${name} example`}</Title>
137	        </div>
138	        <Tabs activeKey={1}>
139	          <Tab title="A" eventKey={0} />
140	          <Tab title="B" eventKey={0} />
141	          <Tab title="C" eventKey={0} />
142	          <Tab title="D" eventKey={0} />
143	          <Tab title="E" eventKey={0} />
144	          <Tab title="Network traffic" eventKey={1}>
145	            {content}
146	          </Tab>
147	        </Tabs>
148	      </PageSection>
149	    );
150	  };
151	
152	  return (
153	    <BrowserRouter>
154	      <Page
155	        masthead={
156	          <Header isDark={isDark} setDark={setDark} isSidebarOpen={isSidebarOpen} onSidebarToggle={onSidebarToggle} />
157	        }
158	        sidebar={
159	          <PageSidebar isSidebarOpen={isSidebarOpen} id="vertical-sidebar">
160	            <PageSidebarBody>
161	              <Nav aria-label="Nav">
162	                <NavList>
163	                  {pages.map((page, index) => (
164	                    <NavItem itemId={index} key={page.id}>
165	                      <NavLink
166	                        id={`${page.id}-nav-item-link`}
167	                        to={`/console-${page.id}`}
168	                        className={({ isActive }) => (isActive ? 'pf-m-current' : '')}
169	                      >
170	                        {page.name}
171	                      </NavLink>
172	                    </NavItem>
173	                  ))}
174	                </NavList>
175	              </Nav>
176	            </PageSidebarBody>
177	          </PageSidebar>
178	        }
179	      >
180	        <Routes>
181	          {pages.map(page => {
182	            if (page.addContext) {
183	              return (
184	                <Route path={`/console-${page.id}`} key={page.id} element={withContext(page.content, page.name)} />
185	              );
186	            }
187	            return <Route path={`/console-${page.id}`} key={page.id} element={page.content} />;
188	          })}
189	          <Route path="*" element={<Navigate to={`/console-${pages[0].id}`} replace />} />
190	        </Routes>
191	      </Page>
192	    </BrowserRouter>
193	  );
194	};
195	
196	export default App;

